import{c as a,Q as s,j as n,m as t}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"The CLAUDE.md File That 10x'd My Output (Full File Included) — @zodchiii","description":"","frontmatter":{"title":"The CLAUDE.md File That 10x'd My Output (Full File Included) — @zodchiii","author":"darkzodchi（@zodchiii）","date":"2026-04-27T00:00:00.000Z","source":"https://x.com/zodchiii/status/2048683276194185640","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-27-@zodchiii-185640.md","filePath":"research/tweets/2026-04-27-@zodchiii-185640.md","lastUpdated":1779894392000}`),i={name:"research/tweets/2026-04-27-@zodchiii-185640.md"};function o(l,e,p,r,c,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="the-claude-md-file-that-10x-d-my-output-full-file-included-—-zodchiii" tabindex="-1">The CLAUDE.md File That 10x&#39;d My Output (Full File Included) — @zodchiii <a class="header-anchor" href="#the-claude-md-file-that-10x-d-my-output-full-file-included-—-zodchiii" aria-label="Permalink to &quot;The CLAUDE.md File That 10x&#39;d My Output (Full File Included) — @zodchiii&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/zodchiii/status/2048683276194185640" target="_blank" rel="noreferrer">https://x.com/zodchiii/status/2048683276194185640</a><strong>作者</strong>：darkzodchi（@zodchiii） <strong>發布日期</strong>：2026-04-27 <strong>收錄日期</strong>：2026-04-27 <strong>類型</strong>：Twitter Article <strong>統計</strong>：167 likes · 19 retweets · 505 bookmarks · 83,014 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p><em>Every Claude Code session starts by reading one file: CLAUDE.md. Before your first prompt, before any code, before anything happens, Claude reads this file and treats it as ground truth for the entire session.</em></p><p>Most people either don&#39;t have one, or theirs is 300 lines of personality instructions.</p><p>The difference between a good CLAUDE.md and a bad one is the difference between onboarding a senior engineer with a clear brief and throwing a new hire into a codebase with no documentation.</p><p>Here&#39;s how to write one that actually works👇</p><p>Before we dive in, I share daily notes on AI &amp; vibe coding in my Telegram channel: <a href="https://t.me/zodchixquant" target="_blank" rel="noreferrer">https://t.me/zodchixquant</a></p><h2 id="why-most-claude-md-files-don-t-work" tabindex="-1">Why most CLAUDE.md files don&#39;t work <a class="header-anchor" href="#why-most-claude-md-files-don-t-work" aria-label="Permalink to &quot;Why most CLAUDE.md files don&#39;t work&quot;">​</a></h2><p>Three reasons:</p><p><strong>Too long.</strong> Models can reliably follow about 150-200 instructions. Claude Code&#39;s system prompt already contains roughly 50. That means your CLAUDE.md gets maybe 100-150 instructions before Claude starts dropping things. If your file is 200+ lines, Claude isn&#39;t ignoring your rules on purpose.</p><p><strong>Wrong content.</strong> Most people fill CLAUDE.md with things Claude can figure out on its own. Personality instructions like &quot;be a senior engineer&quot; or &quot;think step by step.&quot; General advice that doesn&#39;t change Claude&#39;s behavior. Every line that doesn&#39;t prevent a specific mistake is a wasted instruction.</p><p><strong>No hierarchy.</strong> CLAUDE.md isn&#39;t the only place to put instructions. There are three levels and most people dump everything into one:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.claude/CLAUDE.md       → Global (every project)</span></span>
<span class="line"><span>.claude/CLAUDE.md         → Project (shared with team, in git)</span></span>
<span class="line"><span>./CLAUDE.local.md         → Local (personal overrides, gitignored)</span></span></code></pre></div><p>Global is for rules you&#39;d repeat in every project. Project is for stack-specific context your team needs. Local is for your personal quirks.</p><p>Using all three keeps each file short and focused.</p><h2 id="the-5-sections-that-actually-matter" tabindex="-1">The 5 sections that actually matter <a class="header-anchor" href="#the-5-sections-that-actually-matter" aria-label="Permalink to &quot;The 5 sections that actually matter&quot;">​</a></h2><p>After going through dozens of production CLAUDE.md files from open-source projects, Anthropic&#39;s own docs, and community best practices repos, every effective file covers these 5 things:</p><h2 id="_1-critical-commands" tabindex="-1">1. Critical commands <a class="header-anchor" href="#_1-critical-commands" aria-label="Permalink to &quot;1. Critical commands&quot;">​</a></h2><p>Claude doesn&#39;t know how to build, test, or lint your project = tell it.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Commands</span></span>
<span class="line"><span>- Build: \`npm run build\`</span></span>
<span class="line"><span>- Dev: \`npm run dev\`</span></span>
<span class="line"><span>- Test single file: \`npm test -- path/to/file\`</span></span>
<span class="line"><span>- Lint + fix: \`npm run lint:fix\`</span></span>
<span class="line"><span>- Type check: \`npx tsc --noEmit\`</span></span></code></pre></div><p>Short and specific. Claude runs these instead of guessing. Without this section, Claude will try npm test when your project uses pnpm vitest and waste 3 turns debugging a command that was never going to work.</p><h2 id="_2-architecture-map" tabindex="-1">2. Architecture map <a class="header-anchor" href="#_2-architecture-map" aria-label="Permalink to &quot;2. Architecture map&quot;">​</a></h2><p>Claude starts every session with zero knowledge of your codebase. Give it a map.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Architecture</span></span>
<span class="line"><span>- src/lib/services/ → all business logic</span></span>
<span class="line"><span>- src/components/ → stateless UI components only</span></span>
<span class="line"><span>- src/lib/store/ → global state (Zustand)</span></span>
<span class="line"><span>- src/app/api/ → API routes, no business logic here</span></span>
<span class="line"><span>- Database access only through Server Actions or API routes</span></span></code></pre></div><p>Not a full directory listing. Just enough so Claude knows where things live and what goes where.</p><h2 id="_3-hard-rules-the-things-claude-gets-wrong-without-you" tabindex="-1">3. Hard rules (the things Claude gets wrong without you) <a class="header-anchor" href="#_3-hard-rules-the-things-claude-gets-wrong-without-you" aria-label="Permalink to &quot;3. Hard rules (the things Claude gets wrong without you)&quot;">​</a></h2><p>This is the most important section. Every rule here should answer: &quot;Would removing this line cause Claude to make a mistake?&quot;</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Rules</span></span>
<span class="line"><span>- NEVER commit .env files or secrets</span></span>
<span class="line"><span>- All async calls must use try/catch</span></span>
<span class="line"><span>- Use functional components only, no class components</span></span>
<span class="line"><span>- Prefix commits: feat:, fix:, docs:, refactor:</span></span>
<span class="line"><span>- All PRs must pass \`npm run verify\` before merge</span></span>
<span class="line"><span>- Static export only, no SSR (deployed to S3)</span></span>
<span class="line"><span>- IMPORTANT: run type check after every code change</span></span></code></pre></div><p>Two things to notice:</p><ol><li>negative rules are as important as positive ones (&quot;never commit .env&quot;)</li><li>emphasis markers like IMPORTANT actually work.</li></ol><p>Anthropic&#39;s own docs confirm that adding &quot;IMPORTANT&quot; or &quot;YOU MUST&quot; improves adherence.</p><p>Keep this section under 15 rules.</p><h2 id="_4-workflow-preferences" tabindex="-1">4. Workflow preferences <a class="header-anchor" href="#_4-workflow-preferences" aria-label="Permalink to &quot;4. Workflow preferences&quot;">​</a></h2><p>How do you want Claude to work? This prevents the &quot;Claude rewrites your entire file when you asked for a one-line fix&quot; problem.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Workflow</span></span>
<span class="line"><span>- Ask clarifying questions before starting complex tasks</span></span>
<span class="line"><span>- Make minimal changes, don&#39;t refactor unrelated code</span></span>
<span class="line"><span>- Run tests after every change, fix failures before moving on</span></span>
<span class="line"><span>- Create separate commits per logical change, not one giant commit</span></span>
<span class="line"><span>- When unsure between two approaches, explain both and let me choose</span></span></code></pre></div><h2 id="_5-what-not-to-include" tabindex="-1">5. What NOT to include <a class="header-anchor" href="#_5-what-not-to-include" aria-label="Permalink to &quot;5. What NOT to include&quot;">​</a></h2><p>Equally important is what you leave out:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Don&#39;t include:</span></span>
<span class="line"><span>- Personality instructions (&quot;be a senior engineer&quot;)</span></span>
<span class="line"><span>- Code formatting rules your linter already handles</span></span>
<span class="line"><span>- @-imports that embed entire docs into every session</span></span>
<span class="line"><span>- Duplicate rules (if global says &quot;run tests,&quot; project doesn&#39;t repeat it)</span></span>
<span class="line"><span>- Anything Claude will learn on its own via auto memory</span></span></code></pre></div><p><strong>Auto memory</strong> is underrated here. Claude maintains its own notes at <code>~/.claude/projects/&lt;project&gt;/memory/</code>. Run <code>/memory</code> to see what Claude has already learned about your project.</p><p>Don&#39;t waste CLAUDE.md lines on things Claude figured out after one session.</p><h2 id="the-full-template-copy-this" tabindex="-1">The full template (copy this) <a class="header-anchor" href="#the-full-template-copy-this" aria-label="Permalink to &quot;The full template (copy this)&quot;">​</a></h2><p>Here&#39;s a production-ready CLAUDE.md you can copy and adapt. Under 60 lines. Covers everything Claude needs, nothing it doesn&#39;t.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># CLAUDE.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Project</span></span>
<span class="line"><span>[One line: what this project does and who uses it]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Stack</span></span>
<span class="line"><span>[Framework, language, database, deployment target]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Commands</span></span>
<span class="line"><span>- Dev: \`[command]\`</span></span>
<span class="line"><span>- Build: \`[command]\`</span></span>
<span class="line"><span>- Test single: \`[command] -- [path]\`</span></span>
<span class="line"><span>- Test all: \`[command]\`</span></span>
<span class="line"><span>- Lint: \`[command]\`</span></span>
<span class="line"><span>- Type check: \`[command]\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Architecture</span></span>
<span class="line"><span>- [folder] → [what lives here]</span></span>
<span class="line"><span>- [folder] → [what lives here]</span></span>
<span class="line"><span>- [folder] → [what lives here]</span></span>
<span class="line"><span>- [file] → [what this file does]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Rules</span></span>
<span class="line"><span>- [Rule that prevents a specific mistake]</span></span>
<span class="line"><span>- [Rule that prevents a specific mistake]</span></span>
<span class="line"><span>- [Rule that prevents a specific mistake]</span></span>
<span class="line"><span>- IMPORTANT: [The one rule Claude keeps breaking]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Workflow</span></span>
<span class="line"><span>- [How you want Claude to approach tasks]</span></span>
<span class="line"><span>- [Commit conventions]</span></span>
<span class="line"><span>- [Testing expectations]</span></span>
<span class="line"><span>- [When to ask vs when to act]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Out of scope</span></span>
<span class="line"><span>- [Things Claude should not touch]</span></span>
<span class="line"><span>- [Files that are manually maintained]</span></span>
<span class="line"><span>- [Integrations Claude shouldn&#39;t modify]</span></span></code></pre></div><p>Delete sections that don&#39;t apply.</p><h2 id="the-rules-that-change-everything" tabindex="-1">The rules that change everything <a class="header-anchor" href="#the-rules-that-change-everything" aria-label="Permalink to &quot;The rules that change everything&quot;">​</a></h2><p>After testing dozens of CLAUDE.md configurations, these are the lines that made the biggest difference in output quality:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># The lines with highest impact:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- IMPORTANT: run type check after every code change</span></span>
<span class="line"><span>  (prevents Claude from shipping broken types)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Make minimal changes, don&#39;t refactor unrelated code</span></span>
<span class="line"><span>  (prevents Claude from rewriting your entire file)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Create separate commits per logical change</span></span>
<span class="line"><span>  (prevents the 47-file monster commit)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- When unsure, explain both approaches and let me choose</span></span>
<span class="line"><span>  (prevents Claude from making architectural decisions for you)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Static export only, no SSR</span></span>
<span class="line"><span>  (prevents Claude from adding server-side code to a static site)</span></span></code></pre></div><p>Each of these prevents a specific, common mistake.</p><p>That&#39;s the test for every line in your CLAUDE.md: does removing it cause Claude to do the wrong thing?</p><h2 id="the-mistake-everyone-makes" tabindex="-1">The mistake everyone makes <a class="header-anchor" href="#the-mistake-everyone-makes" aria-label="Permalink to &quot;The mistake everyone makes&quot;">​</a></h2><p>People treat CLAUDE.md like a wish list.</p><p>Your CLAUDE.md should be a technical brief, not a motivational speech. Stack, commands, architecture, rules, workflow. Everything else is noise competing for attention with the instructions that actually matter.</p><p>Keep it under 80 lines. Review it when Claude gets something wrong.</p><p>The file compounds over time. A good CLAUDE.md in month one saves you from repeating yourself.</p><p>By month six it&#39;s captured every mistake Claude has ever made in your project and prevents all of them automatically.</p><p>I share daily notes on AI, finance, and vibe coding in my Telegram channel: <a href="https://t.me/zodchixquant" target="_blank" rel="noreferrer">https://t.me/zodchixquant</a></p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：CLAUDE.md 應是技術 brief 而非願望清單，三層架構（Global/Project/Local）加五個核心段落是最高效寫法。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Claude 可靠跟隨約 150-200 條指令，系統 prompt 佔 ~50 條，留給 CLAUDE.md 的預算約 100-150 條</li><li>三層架構：Global（每個專案共用）/ Project（團隊共享）/ Local（個人覆寫）</li><li>五個有效段落：Commands、Architecture、Hard Rules、Workflow Preferences、What NOT to include</li><li><code>IMPORTANT:</code> / <code>YOU MUST</code> 等強調標記確實提升遵從率（Anthropic 文件確認）</li><li>Auto Memory 會自動學習專案知識，不需在 CLAUDE.md 重複</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>150-200 條：模型可靠跟隨的指令上限</li><li>~50 條：Claude Code 系統 prompt 已佔用的指令數</li><li>80 行以下：建議的 CLAUDE.md 長度上限</li><li>60 行：作者提供的模板行數</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>「150-200 指令上限」是作者個人測試結論，並無 Anthropic 官方數據支撐，適用性因指令複雜度而異</li><li>「Anthropic&#39;s own docs confirm」語焉不詳，本 workspace 的 CLAUDE.md 已有分層載入（auto/on-demand/manual），實際上比文章建議的更複雜也更有效</li><li>文章建議 80 行上限，而 cc-workspace 的 CLAUDE.md 採 lazy-load 架構（CLAUDE.md 本身保持短小，詳細規則按需載入），是更好的解法</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>直接針對 CLAUDE.md，cc-workspace 可對照現有結構驗證</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>五段落框架是整理而非新發現，auto memory 觀點值得一記</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>「150-200 指令上限」等關鍵數據無來源，主要是個人經驗</td></tr><tr><td>D. 技術深度 (15%)</td><td>7/10</td><td>含可直接複製的模板與程式碼範例，實用性高</td></tr><tr><td>E. 泛化性 (15%)</td><td>9/10</td><td>適用所有 Claude Code 使用者，無專案鎖定</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.65/10</strong></td><td>8×0.3+5×0.2+4×0.2+7×0.15+9×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：五段落框架與三層架構可補充或驗證現有 <code>core.md</code>；「IMPORTANT 標記有效」值得在 rules 中加強說明。</p>`,71)])])}const m=a(i,[["render",o]]);export{u as __pageData,m as default};
